INSERT INTO public.organisations (name, category, ombudsman_name, escalation_wait_weeks)
SELECT v.name, v.cat::text, v.obm, v.ew
FROM (
  VALUES
    ('British Gas', 'energy', 'Energy Ombudsman', 8),
    ('E.ON', 'energy', 'Energy Ombudsman', 8),
    ('EDF', 'energy', 'Energy Ombudsman', 8),
    ('OVO Energy', 'energy', 'Energy Ombudsman', 8),
    ('Scottish Power', 'energy', 'Energy Ombudsman', 8),
    ('Octopus Energy', 'energy', 'Energy Ombudsman', 8),
    ('EE', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('TalkTalk', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('Vodafone', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('Virgin Media', 'broadband_phone', 'CISAS', 8),
    ('BT', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('Three', 'broadband_phone', 'CISAS', 8),
    ('O2', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('Sky', 'broadband_phone', 'Ombudsman Services: Communications', 8),
    ('Barclays', 'financial_services', 'Financial Ombudsman Service', 8),
    ('HSBC', 'financial_services', 'Financial Ombudsman Service', 8),
    ('Santander', 'financial_services', 'Financial Ombudsman Service', 8),
    ('Lloyds Bank', 'financial_services', 'Financial Ombudsman Service', 8),
    ('NatWest', 'financial_services', 'Financial Ombudsman Service', 8),
    ('Ryanair', 'transport', NULL, 8),
    ('easyJet', 'transport', NULL, 8),
    ('British Airways', 'transport', NULL, 8)
) AS v(name, cat, obm, ew)
WHERE NOT EXISTS (
  SELECT 1 FROM public.organisations o WHERE lower(trim(o.name)) = lower(trim(v.name))
);

-- Shared placeholder JSON fragments
-- your_rights / content: one starter card; escalation_steps / step_by_step: 3 steps; faq: 3 items; common_issues: 3 items

INSERT INTO public.seo_organisation_pages (
  organisation_id, slug, page_title, meta_description, sector, hero_heading, hero_subheading,
  your_rights, escalation_steps, faq_items, common_issues,
  ombudsman_name, ombudsman_slug, regulator_name, primary_legislation, complaint_deadline_days,
  related_guide_slugs, related_org_slugs, status, published_at
)
SELECT o.id, d.slug, d.page_title, d.meta_description, d.sector, d.hero_heading, d.hero_subheading,
  d.your_rights::jsonb, d.escalation_steps::jsonb, d.faq_items::jsonb, d.common_issues::jsonb,
  d.ombudsman_name, d.ombudsman_slug, d.regulator_name, d.primary_legislation, d.complaint_deadline_days::integer,
  d.related_guide_slugs, d.related_org_slugs, 'published', now()
FROM public.organisations o
JOIN (
  VALUES
    ('British Gas', 'british-gas', 'How to Complain to British Gas',
      'Step-by-step complaints against British Gas: your rights, deadlines, and escalation to the Energy Ombudsman. Draft a formal letter with TheyPromised.',
      'energy', $h$British Gas won't resolve your complaint?$h$, $s$Use UK energy rules to escalate fairly. TheyPromised helps you log evidence and draft a formal complaint in minutes.$s$,
      $json$[{"heading":"Fair complaints handling","body":"Energy suppliers must handle complaints under licence conditions and standards set by the regulator. This page will be expanded with firm-specific detail.","legislation_ref":"Gas Act 1986; Electricity Act 1989"}]$json$,
      $json$[{"step_number":1,"title":"Complain to British Gas","description":"Use their complaints process and keep a reference number.","deadline_days":null,"legislation_ref":"Ofgem Standards of Conduct"},{"step_number":2,"title":"Wait for a final response","description":"Typically up to eight weeks for an unresolved complaint before escalation.","deadline_days":56,"legislation_ref":"Energy company licence conditions"},{"step_number":3,"title":"Energy Ombudsman","description":"Free, independent dispute resolution if you remain unhappy.","deadline_days":null,"legislation_ref":"Alternative Dispute Resolution"}]$json$,
      $json$[{"question":"How long should British Gas take?","answer":"Many complaints should be resolved within eight weeks; complex cases can vary. Check your final response letter for the exact position."},{"question":"Can I go to the Energy Ombudsman?","answer":"Usually after eight weeks from your complaint or if you have a deadlock letter. Verify current rules on the Energy Ombudsman website."},{"question":"Is this legal advice?","answer":"No. This guide is for general information; verify deadlines with official sources."}]$json$,
      $json$[{"issue":"Billing and direct debits","description":"Estimated bills, balance disputes, and payment plans."},{"issue":"Smart meters","description":"Installation, readings, and communication faults."},{"issue":"Customer service delays","description":"Long waits and poor complaint handling."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989','Consumer Rights Act 2015']::text[], 56,
      ARRAY['energy-ombudsman-escalation','energy-billing-disputes']::text[],
      ARRAY['edf','eon','ovo-energy','octopus-energy','scottish-power']::text[]),
    ('E.ON', 'eon', 'How to Complain to E.ON',
      'Complain to E.ON with clear steps, regulator context, and escalation options including the Energy Ombudsman.',
      'energy', $h$Issues with E.ON billing or service?$h$, $s$Document every contact and escalate using the same protections that apply across licensed energy suppliers.$s$,
      $json$[{"heading":"Licensed supplier obligations","body":"E.ON must meet standards for complaints and vulnerable customers under licence and regulatory rules.","legislation_ref":"Gas Act 1986; Electricity Act 1989"}]$json$,
      $json$[{"step_number":1,"title":"Formal complaint to E.ON","description":"Raise via phone, webform, or post and retain evidence.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Eight-week review","description":"If still unresolved, note the date for ombudsman eligibility.","deadline_days":56,"legislation_ref":null},{"step_number":3,"title":"Energy Ombudsman","description":"Independent resolution for eligible complaints.","deadline_days":null,"legislation_ref":null}]$json$,
      $json$[{"question":"Can I switch while complaining?","answer":"You can usually switch; outstanding balances may still apply. Check E.ON and Ofgem guidance."},{"question":"What if my supply is at risk?","answer":"Contact Citizens Advice for urgent vulnerability or disconnection issues."},{"question":"Do I pay for the ombudsman?","answer":"The Energy Ombudsman service is free to consumers."}]$json$,
      $json$[{"issue":"Tariff confusion","description":"Fixed vs variable charges and exit fees."},{"issue":"Meter problems","description":"Faulty or inaccessible meters."},{"issue":"Back-billing","description":"Large catch-up bills and back-billing rules."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989']::text[], 56,
      ARRAY['energy-ombudsman-escalation']::text[],
      ARRAY['british-gas','edf','ovo-energy','octopus-energy','scottish-power']::text[]),
    ('EDF', 'edf', 'How to Complain to EDF',
      'EDF complaints: your rights, typical issues, and how to escalate beyond the supplier when deadlines are missed.',
      'energy', $h$EDF not fixing your problem?$h$, $s$Follow the regulated path from internal complaint to the Energy Ombudsman where appropriate.$s$,
      $json$[{"heading":"Consumer protections","body":"Domestic energy complaints are governed by licence conditions and consumer law.","legislation_ref":"Consumer Rights Act 2015"}]$json$,
      $json$[{"step_number":1,"title":"EDF complaints team","description":"Log the issue formally and request a written outcome.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Track the eight-week window","description":"Note when you can escalate if there is no fair resolution.","deadline_days":56,"legislation_ref":null},{"step_number":3,"title":"Energy Ombudsman","description":"Escalate eligible complaints for a binding decision.","deadline_days":null,"legislation_ref":null}]$json$,
      $json$[{"question":"What evidence helps?","answer":"Bills, emails, chat transcripts, and call notes with dates and adviser names."},{"question":"Can I claim compensation?","answer":"The ombudsman can award compensation where appropriate; outcomes depend on facts."},{"question":"Where do I read official rules?","answer":"Use Ofgem and the Energy Ombudsman for the latest process details."}]$json$,
      $json$[{"issue":"Nuclear levy or tariff lines on bills","description":"Questions about charges and plan terms."},{"issue":"Smart meter appointments","description":"Missed or rearranged appointments."},{"issue":"Complaint handling delays","description":"Slow responses or unclear outcomes."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989']::text[], 56,
      ARRAY['energy-ombudsman-escalation','energy-billing-disputes']::text[],
      ARRAY['british-gas','eon','ovo-energy','octopus-energy','scottish-power']::text[]),
    ('OVO Energy', 'ovo-energy', 'How to Complain to OVO Energy',
      'OVO Energy complaints guide: deadlines, ombudsman escalation, and how to keep an evidence trail.',
      'energy', $h$OVO Energy complaint stuck?$h$, $s$Licensed suppliers must treat complaints fairly; here is the standard UK escalation route.$s$,
      $json$[{"heading":"Standards of conduct","body":"Suppliers must meet Ofgem-backed standards including clear complaints handling.","legislation_ref":"Ofgem Standards of Conduct"}]$json$,
      $json$[{"step_number":1,"title":"OVO complaint","description":"Use OVO channels and keep references.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Final response","description":"Request a clear deadlock or final position if needed.","deadline_days":null,"legislation_ref":null},{"step_number":3,"title":"Energy Ombudsman","description":"Escalate within scheme time limits.","deadline_days":null,"legislation_ref":null}]$json$,
      $json$[{"question":"What is a deadlock letter?","answer":"A letter saying the supplier will not change its position — often used to escalate sooner."}]$json$,
      $json$[{"issue":"Pay monthly reviews","description":"Direct debit changes and payment plans."},{"issue":"Switching blocks","description":"Objections or delays when moving supplier."},{"issue":"Customer service","description":"Repeat contacts without resolution."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989']::text[], 56,
      ARRAY['energy-ombudsman-escalation']::text[],
      ARRAY['british-gas','edf','eon','octopus-energy','scottish-power']::text[]),
    ('Scottish Power', 'scottish-power', 'How to Complain to Scottish Power',
      'Scottish Power complaints: regulator context, typical disputes, and Energy Ombudsman escalation.',
      'energy', $h$Scottish Power complaint not sorted?$h$, $s$Use the same statutory framework as other large domestic suppliers.$s$,
      $json$[{"heading":"Energy supply complaints","body":"Complaints about supply, billing, and service are covered by energy licensing and consumer law.","legislation_ref":"Electricity Act 1989"}]$json$,
      $json$[{"step_number":1,"title":"Scottish Power complaints","description":"Raise formally and chase in writing.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Eight-week checkpoint","description":"Assess ombudsman eligibility if unresolved.","deadline_days":56,"legislation_ref":null},{"step_number":3,"title":"Energy Ombudsman","description":"Independent review for eligible cases.","deadline_days":null,"legislation_ref":null}]$json$,
      $json$[{"question":"Is there a time limit for the ombudsman?","answer":"Yes — check the Energy Ombudsman website for current limits from your final response or eight-week date."}]$json$,
      $json$[{"issue":"Billing disputes","description":"Incorrect charges or estimates."},{"issue":"Prepayment meters","description":"Token, key, or smart PAYG faults."},{"issue":"Warm home discount","description":"Eligibility and administration issues."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989']::text[], 56,
      ARRAY['energy-ombudsman-escalation']::text[],
      ARRAY['british-gas','edf','eon','ovo-energy','octopus-energy']::text[]),
    ('Octopus Energy', 'octopus-energy', 'How to Complain to Octopus Energy',
      'Octopus Energy complaints: how to escalate fairly and when the Energy Ombudsman can step in.',
      'energy', $h$Octopus Energy not responding fairly?$h$, $s$Keep a timeline of contacts and use the regulated complaints path.$s$,
      $json$[{"heading":"Regulatory framework","body":"Octopus, like all domestic suppliers, must meet licence complaints standards.","legislation_ref":"Gas Act 1986"}]$json$,
      $json$[{"step_number":1,"title":"Octopus complaints","description":"Use official routes and save confirmations.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Assess resolution","description":"If unhappy after the allowed period, prepare to escalate.","deadline_days":56,"legislation_ref":null},{"step_number":3,"title":"Energy Ombudsman","description":"Free ADR for eligible complaints.","deadline_days":null,"legislation_ref":null}]$json$,
      $json$[{"question":"Does Octopus publish complaint data?","answer":"Ofgem publishes broad industry data; use it as context, not a prediction of your outcome."}]$json$,
      $json$[{"issue":"Agile / smart tariffs","description":"Complex pricing and display issues."},{"issue":"Referrals and credit balances","description":"Final bills and refunds."},{"issue":"Smart meter communications","description":"Connectivity and billing impacts."}]$json$,
      'Energy Ombudsman', 'energy-ombudsman-escalation', 'Ofgem',
      ARRAY['Gas Act 1986','Electricity Act 1989']::text[], 56,
      ARRAY['energy-ombudsman-escalation']::text[],
      ARRAY['british-gas','edf','eon','ovo-energy','scottish-power']::text[])
) AS d(org_name, slug, page_title, meta_description, sector, hero_heading, hero_subheading, your_rights, escalation_steps, faq_items, common_issues, ombudsman_name, ombudsman_slug, regulator_name, primary_legislation, complaint_deadline_days, related_guide_slugs, related_org_slugs)
  ON lower(trim(o.name)) = lower(trim(d.org_name))
ON CONFLICT (slug) DO NOTHING;

