      $json$[{"step_number":1,"title":"easyJet complaint","description":"Submit via easyJet channels.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Written outcome","description":"Challenge unclear refusals with evidence.","deadline_days":null,"legislation_ref":null},{"step_number":3,"title":"ADR or court","description":"Where offered and proportionate.","deadline_days":null,"legislation_ref":null}]$json$,
