      $h$BA complaint unresolved?$h$, $s$Long-haul and short-haul rules differ under UK261.$s$,
      $json$[{"heading":"Layered rights","body":"Flight disruption, baggage, and service complaints may involve different legal bases.","legislation_ref":"Montreal Convention; UK261"}]$json$,
      $json$[{"step_number":1,"title":"BA complaint","description":"Use BA customer relations.","deadline_days":null,"legislation_ref":null},{"step_number":2,"title":"Escalate in writing","description":"Clear chronology and desired outcome.","deadline_days":null,"legislation_ref":null},{"step_number":3,"title":"ADR / court","description":"Consider CEDR or court routes where appropriate.","deadline_days":null,"legislation_ref":null}]$json$,
