INSERT INTO public.seo_guide_pages (
  slug, page_title, meta_description, category, sector, hero_heading, hero_subheading,
  introduction, content_sections, eligibility_criteria, step_by_step, faq_items,
  primary_legislation, key_deadlines, related_org_slugs, related_guide_slugs, status, published_at
) VALUES
(
  'energy-ombudsman-escalation',
  'How to Escalate to the Energy Ombudsman',
  'When and how to escalate energy complaints to the Energy Ombudsman after eight weeks or a deadlock letter.',
  'ombudsman', 'energy',
  $gh$Escalate an unresolved energy complaint$gh$,
  $gs$Free, independent dispute resolution for many domestic energy complaints.$gs$,
  $gi$If your supplier has not resolved your complaint within the required timeframe, or has issued a deadlock letter, you may be able to refer the matter to the Energy Ombudsman.$gi$,
  $json$[{"heading":"Eligibility basics","body":"Eligibility depends on your complaint type, supplier licence, and whether internal processes have completed. Always confirm on the Energy Ombudsman website.","legislation_ref":"Energy company licence conditions"}]$json$::jsonb,
  $json$[{"criterion":"Domestic consumer","description":"Most schemes focus on domestic customers."},{"criterion":"Time limits","description":"Refer within the ombudsman’s published limits."}]$json$::jsonb,
  $json$[{"step_number":1,"title":"Complete supplier process","description":"Raise a formal complaint and keep references.","tip":"Write down dates and adviser names."},{"step_number":2,"title":"Eight weeks or deadlock","description":"Check if you can refer now.","tip":"A deadlock letter can shorten the wait."},{"step_number":3,"title":"Submit to ombudsman","description":"Provide a clear chronology and evidence.","tip":"Attach bills and final responses."}]$json$::jsonb,
  $json$[{"question":"Does it cost money?","answer":"No — the Energy Ombudsman is free to consumers."},{"question":"Is the decision binding?","answer":"If you accept the outcome, it is binding on the supplier; you can reject and pursue other routes in some cases."}]$json$::jsonb,
  ARRAY['Gas Act 1986','Electricity Act 1989']::text[],
  $json$[{"description":"Typical internal resolution window","days":56,"from_event":"Formal complaint opened"}]$json$::jsonb,
  ARRAY['british-gas','edf','ovo-energy']::text[],
  ARRAY['energy-billing-disputes']::text[],
  'published', now()
),
(
  'ofcom-complaint',
  'How to Complain to Ofcom',
  'How Ofcom regulates telecoms and how consumer complaints reach approved ADR schemes.',
  'ombudsman', 'telecoms',
  $gh$Ofcom’s role in telecoms complaints$gh$,
  $gs$Ofcom sets rules; approved ombudsman schemes resolve many deadlocked disputes.$gs$,
  $gi$Ofcom does not usually resolve individual complaints like a court, but providers must comply with general conditions including complaints handling and access to ADR.$gi$,
  $json$[{"heading":"General conditions","body":"Providers must have complaints codes and tell you about ADR when eligible.","legislation_ref":"Communications Act 2003"}]$json$::jsonb,
  '[]'::jsonb,
  $json$[{"step_number":1,"title":"Complain to your provider","description":"Follow their code of practice.","tip":null},{"step_number":2,"title":"Request a deadlock letter","description":"If stuck after eight weeks or as per rules.","tip":null},{"step_number":3,"title":"ADR referral","description":"Use CISAS or Ombudsman Services as directed.","tip":null}]$json$::jsonb,
  $json$[{"question":"Can Ofcom fine my provider?","answer":"Ofcom can enforce against providers; that is separate from individual redress through ADR."}]$json$::jsonb,
  ARRAY['Communications Act 2003']::text[],
  $json$[{"description":"Typical ADR referral window","days":56,"from_event":"Complaint opened"}]$json$::jsonb,
  ARRAY['bt','ee','sky']::text[],
  ARRAY['broadband-speed-complaints']::text[],
  'published', now()
),
(
  'financial-ombudsman-complaint',
  'How to Complain to the Financial Ombudsman Service',
  'FOS eligibility, DISP timelines, and how to refer banking and credit complaints.',
  'ombudsman', 'financial',
  $gh$Financial Ombudsman Service referrals$gh$,
  $gs$Free dispute resolution for many eligible regulated complaints.$gs$,
  $gi$After a final response from your firm, or after eight weeks for many complaints, you may refer eligible disputes to the Financial Ombudsman Service within published time limits.$gi$,
  $json$[{"heading":"DISP framework","body":"Firms must handle complaints under FCA DISP rules for eligible complaints.","legislation_ref":"FCA Handbook DISP"}]$json$::jsonb,
  $json$[{"criterion":"Eligible complainant","description":"Definitions differ for consumers, micro-enterprises, and charities."}]$json$::jsonb,
  $json$[{"step_number":1,"title":"Complain to the firm","description":"Use the internal process.","tip":null},{"step_number":2,"title":"Final response","description":"Check the FOS leaflet enclosed.","tip":null},{"step_number":3,"title":"Refer to FOS","description":"Submit within the time limit stated.","tip":null}]$json$::jsonb,
  $json$[{"question":"Six-month rule?","answer":"FOS applies time limits from your final response — verify the current rules on the FOS website."}]$json$::jsonb,
  ARRAY['Financial Services and Markets Act 2000','FCA Handbook (DISP)']::text[],
  $json$[{"description":"Final response deadline (many complaints)","days":56,"from_event":"Complaint received by firm"}]$json$::jsonb,
  ARRAY['barclays','hsbc','natwest']::text[],
  ARRAY['section-75-claim','chargeback-guide']::text[],
  'published', now()
),
(
  'section-75-claim',
  'Section 75 Claim Guide',
  'Consumer Credit Act 1974 section 75: when your credit card issuer may share liability with the supplier.',
  'legislation', NULL,
  $gh$Section 75 protections on credit card purchases$gh$,
  $gs$May apply to qualifying purchases over £100 on a UK-regulated credit agreement.$gs$,
  $gi$Section 75 can make the creditor jointly liable with the supplier for misrepresentation or breach of contract in certain circumstances. Eligibility is fact-specific.$gi$,
  $json$[{"heading":"Statutory basis","body":"The protection comes from the Consumer Credit Act 1974.","legislation_ref":"Consumer Credit Act 1974 section 75"}]$json$::jsonb,
  $json$[{"criterion":"Minimum amount","description":"Over £100 and usually not more than £30,000 (technical rules apply)."},{"criterion":"Debtor-creditor-supplier chain","description":"The transaction must meet the statutory chain requirements."}]$json$::jsonb,
  $json$[{"step_number":1,"title":"Gather evidence","description":"Contracts, adverts, and proof of payment.","tip":null},{"step_number":2,"title":"Claim to card issuer","description":"Write a formal section 75 claim.","tip":null},{"step_number":3,"title":"FOS if deadlocked","description":"If eligible after final response.","tip":null}]$json$::jsonb,
  $json$[{"question":"Does it apply to debit cards?","answer":"Generally no — chargeback is the main card scheme route for debit."}]$json$::jsonb,
  ARRAY['Consumer Credit Act 1974']::text[],
  $json$[{"description":"FOS referral limit from final response","days":180,"from_event":"Final response (verify current FOS rules)"}]$json$::jsonb,
  ARRAY[]::text[],
  ARRAY['chargeback-guide','financial-ombudsman-complaint']::text[],
  'published', now()
),
(
  'consumer-rights-act-2015',
  'Consumer Rights Act 2015: Your Rights',
  'Core UK consumer rights for goods, services, and unfair terms under the Consumer Rights Act 2015.',
  'legislation', NULL,
  $gh$Consumer Rights Act 2015 essentials$gh$,
  $gs$Sets statutory rights for faulty goods, substandard services, and unfair contract terms.$gs$,
  $gi$The CRA 2015 consolidates and updates consumer law for most business-to-consumer contracts in the UK.$gi$,
  $json$[{"heading":"Goods must be satisfactory","body":"Goods must be as described, fit for purpose, and of satisfactory quality.","legislation_ref":"Consumer Rights Act 2015"}]$json$::jsonb,
  '[]'::jsonb,
  $json$[{"step_number":1,"title":"Identify the problem","description":"Good, digital content, or service failure.","tip":null},{"step_number":2,"title":"Remedy route","description":"Repair, replacement, price reduction, or repeat performance depending on context.","tip":null},{"step_number":3,"title":"Escalate","description":"ADR, ombudsman, or court as appropriate.","tip":null}]$json$::jsonb,
  $json$[{"question":"Is there always a refund?","answer":"Remedies depend on timing and whether the fault is minor — check Citizens Advice summaries."}]$json$::jsonb,
  ARRAY['Consumer Rights Act 2015']::text[],
  '[]'::jsonb,
  ARRAY[]::text[],
  ARRAY['deadlock-letter']::text[],
  'published', now()
),
(
  'flight-delay-compensation',
  'Flight Delay Compensation Guide',
  'UK261 / retained EU261: when compensation may be due for delay, cancellation, and denied boarding.',
  'rights', 'travel',
  $gh$UK flight disruption compensation basics$gh$,
  $gs$Compensation depends on distance, delay length, and whether the flight falls under UK261.$gs$,
  $gi$UK261 provides a structured regime for many qualifying flights from UK carriers and flights departing the UK, subject to specific tests and defences.$gi$,
  $json$[{"heading":"Key cases","body":"Court decisions such as Huzar v Jet2 shaped how extraordinary circumstances are interpreted — verify current guidance.","legislation_ref":"UK261"}]$json$::jsonb,
  $json$[{"criterion":"Qualifying flight","description":"Check departure/arrival and carrier rules."}]$json$::jsonb,
  $json$[{"step_number":1,"title":"Collect proof","description":"Boarding pass, delay announcement, emails.","tip":null},{"step_number":2,"title":"Claim from airline","description":"Use the carrier’s EU261/UK261 form.","tip":null},{"step_number":3,"title":"ADR or court","description":"If refused and you remain eligible.","tip":null}]$json$::jsonb,
  $json$[{"question":"Food and hotel costs?","answer":"Care and assistance rules apply in many qualifying delays — check UK261 text and CAA guidance."}]$json$::jsonb,
  ARRAY['UK261 (retained EU Regulation 261/2004)']::text[],
  $json$[{"description":"Limitation for court claims","days":1095,"from_event":"Flight date (verify limitation rules)"}]$json$::jsonb,
  ARRAY['british-airways','easyjet','ryanair']::text[],
  ARRAY['consumer-rights-act-2015']::text[],
  'published', now()
),
(
  'chargeback-guide',
  'Chargeback Guide',
  'Visa and Mastercard chargeback: a card-scheme dispute route separate from section 75.',
  'process', 'financial',
  $gh$Chargeback disputes on card payments$gh$,
  $gs$Banks raise disputes through card scheme rules — not identical to section 75.$gs$,
  $gi$Chargeback can help where goods or services were not provided or were defective, subject to scheme reason codes and issuer discretion.$gi$,
  $json$[{"heading":"Scheme rules","body":"Visa and Mastercard maintain chargeback reason codes and time limits.","legislation_ref":"Visa/Mastercard scheme rules"}]$json$::jsonb,
  $json$[{"criterion":"Time limits","description":"Often 120 days from expected delivery — confirm with your issuer."}]$json$::jsonb,
  $json$[{"step_number":1,"title":"Contact your bank","description":"Request chargeback with evidence.","tip":null},{"step_number":2,"title":"Issuer investigation","description":"The merchant may respond.","tip":null},{"step_number":3,"title":"Outcome","description":"Temporary credit may be reversed if the dispute fails.","tip":null}]$json$::jsonb,
  $json$[{"question":"Chargeback vs section 75?","answer":"They are different mechanisms; sometimes both are explored with professional guidance."}]$json$::jsonb,
  ARRAY['Visa/Mastercard scheme rules']::text[],
  $json$[{"description":"Typical chargeback window","days":120,"from_event":"Expected delivery or service date"}]$json$::jsonb,
  ARRAY['barclays','hsbc']::text[],
  ARRAY['section-75-claim']::text[],
  'published', now()
),
(
  'deadlock-letter',
  'How to Get a Deadlock Letter',
  'What a deadlock letter is and how it unlocks ombudsman and ADR routes across sectors.',
  'process', NULL,
  $gh$Deadlock letters explained$gh$,
  $gs$A clear “final position” can start the clock for external dispute resolution.$gs$,
  $gi$Many ombudsman schemes require a final response or a defined complaint age. A deadlock letter states the business will not change its position.$gi$,
  $json$[{"heading":"Why it matters","body":"It can demonstrate you have exhausted internal processes.","legislation_ref":"Various ombudsman scheme rules"}]$json$::jsonb,
  '[]'::jsonb,
  $json$[{"step_number":1,"title":"Ask in writing","description":"Request a written final response.","tip":null},{"step_number":2,"title":"Set out remaining issues","description":"Bullet unresolved points.","tip":null},{"step_number":3,"title":"Escalate","description":"Use the scheme named in the letter.","tip":null}]$json$::jsonb,
  $json$[{"question":"Can I invent a deadlock?","answer":"No — it should reflect the firm’s genuine final position; misrepresentation can harm your case."}]$json$::jsonb,
  ARRAY[]::text[],
  '[]'::jsonb,
  ARRAY[]::text[],
  ARRAY['energy-ombudsman-escalation','financial-ombudsman-complaint']::text[],
  'published', now()
),
(
  'energy-billing-disputes',
  'Energy Billing Disputes Guide',
  'Back-billing, estimates, and wrong tariffs: how energy billing complaints are regulated.',
  'rights', 'energy',
  $gh$Challenge incorrect energy bills$gh$,
  $gs$Licence conditions and standards limit certain back-billing and require fair treatment.$gs$,
  $gi$If your bill looks wrong, you can challenge it with evidence. Ofgem rules on back-billing and customer service standards often apply.$gi$,
  $json$[{"heading":"Back-billing rules","body":"Suppliers must follow Ofgem back-billing rules for domestic consumers in many situations.","legislation_ref":"Ofgem back-billing rules"}]$json$::jsonb,
  '[]'::jsonb,
  $json$[{"step_number":1,"title":"Check meter data","description":"Compare opening/closing reads.","tip":null},{"step_number":2,"title":"Formal complaint","description":"Ask for a written calculation.","tip":null},{"step_number":3,"title":"Ombudsman","description":"If eligible after the process.","tip":null}]$json$::jsonb,
